/**
 * Irrigation crop data — BRL/COM irrigation memento (Bas-Rhône Languedoc / Compagnie Nationale d'Aménagement).
 *
 * 35 crops with annual water consumption (ETc) and net irrigation requirement,
 * plus an 18-value decadal (10-day) irrigation distribution covering Apr–Sep
 * (3 decades per month × 6 months). Decadal values are generated by a triangular
 * kernel centred on the crop's peak-demand month and normalised so the sum
 * approximates `annual_irrigation_mm`. Decades outside the crop's season are 0.
 *
 * Annual figures are taken verbatim from the BRL/COM memento. Per-crop season
 * windows and peak months are agronomic defaults (Mediterranean France).
 */

export type CropCategory = 'vegetable' | 'fruit' | 'cereal' | 'industrial' | 'forage';

export interface CropIrrigationData {
  id: string;
  name_fr: string;
  name_en: string;
  category: CropCategory;
  /** Total seasonal crop evapotranspiration (mm). */
  annual_consumption_mm: number;
  /** Net seasonal irrigation requirement (mm) = ETc − effective rainfall. */
  annual_irrigation_mm: number;
  /** 18 decadal irrigation depths (mm), Apr-D1 … Sep-D3, summing ≈ annual_irrigation_mm. */
  decadal_irrigation_mm: number[];
  /** Human-readable season window (e.g. "Apr–Sep"). */
  season_months: string;
  notes: string;
}

/** 18 decade labels: 3 per month for April through September. */
export const DECADAL_MONTHS = [
  'Apr-D1', 'Apr-D2', 'Apr-D3',
  'May-D1', 'May-D2', 'May-D3',
  'Jun-D1', 'Jun-D2', 'Jun-D3',
  'Jul-D1', 'Jul-D2', 'Jul-D3',
  'Aug-D1', 'Aug-D2', 'Aug-D3',
  'Sep-D1', 'Sep-D2', 'Sep-D3',
] as const;

/**
 * Build an 18-value decadal irrigation distribution using a triangular kernel.
 * The kernel rises linearly from `seasonStart` to `peak` and falls linearly
 * from `peak` to `seasonEnd`. Values outside [seasonStart, seasonEnd] are 0.
 * The kernel is then normalised so the rounded sum approximates `annual`.
 */
function buildDecadal(
  annual: number,
  seasonStart: number,
  seasonEnd: number,
  peak: number,
): number[] {
  const arr = new Array(18).fill(0);
  const leftSpan = Math.max(1, peak - seasonStart + 1);
  const rightSpan = Math.max(1, seasonEnd - peak + 1);
  let total = 0;
  for (let i = seasonStart; i <= seasonEnd; i++) {
    const w = i <= peak ? (i - seasonStart + 1) / leftSpan : (seasonEnd - i + 1) / rightSpan;
    arr[i] = w;
    total += w;
  }
  for (let i = 0; i < 18; i++) {
    arr[i] = total > 0 ? Math.round((annual * arr[i]) / total) : 0;
  }
  return arr;
}

