/** Lookup a single crop by id. */
export function getCropIrrigation(id: string): CropIrrigationData | undefined {
  return CROP_IRRIGATION_DATA.find((c) => c.id === id);
}

/** Filter crops by category. */
export function getCropsByCategory(category: CropCategory): CropIrrigationData[] {
  return CROP_IRRIGATION_DATA.filter((c) => c.category === category);
}
